      typedef struct BinNode *Position;
      typedef struct Collection *BinQueue;
      typedef struct BinNode *BinTree;
      struct BinNode
      {
        ElementType Element;
        Position LeftChild;
        Position NextSibling;
      };
      struct Collection
      {
        int CurrentSize;
        BinTree TheTrees[MaxTrees];
      };
    </code></pre> <ul> <li>Merge：单次复杂度 \(O(\log n)\) ， 均摊 \(O(1)\)</li> <li>二项树的合并，显然 \(O(1)\)，两个堆的合并类似于两个二进制数逐位做加法</li> </ul>  两棵树的合并  <pre><code>
      BinTree CombineTrees( BinTree T1, BinTree T2 )
      {
        if(T1-&gt;Element &gt; T2-&gt;Element) return CombineTrees(T2,T1);
        T2-&gt;NextSibling = T1-&gt;LeftChild;
        T1-&gt;LeftChild = T2;
        return T1;
      }
    </code></pre>  两个二项堆的合并  <pre><code>
      BinQueue Merge( BinQueue H1, BinQueue H2 )
      {
        BinTree T1,T2,Carry = NULL;
        int i,j;
        if( H1-&gt;CurrentSize + H2-&gt;CurrentSize &gt; Capacity ) ErrorMessage();
        H1-&gt;CurrentSize += H2-&gt;CurrentSize;
        for( i = 0; j = 1; j &lt;= H1-&gt;CurrentSize; ++i, j *= 2){
            T1 = H1-&gt;TheTrees[i];
            T2 = H2-&gt;TheTrees[i];
            switch(4*!!Carry + 2*!!T2 + !!T1){
                case 0:case 1:break;
                case 2: H1-&gt;TheTrees[i] = T2;
                        H2-&gt;TheTrees[i] = NULL;break;
                case 4: H1-&gt;TheTrees[i] = Carry;
                        Carry = NULL;break;
                case 3: Carry = CombineTrees( T1, T2 );
                        H1-&gt;TheTrees[i] = H2-&gt;TheTrees[i] = NULL;break;
                case 5: Carry = CombineTrees( T1, Carry );
                        H1-&gt;TheTrees[i] = NULL;break;
                case 6: Carry = CombineTrees( T2, Carry );
                        H2-&gt;TheTrees[i] = NULL; break;
                case 7: H1-&gt;TheTrees[i] = Carry; 
                        Carry = CombineTrees( T1, T2 ); 
                        H2-&gt;TheTrees[i] = NULL; break;
            }
        }
        return H1;
      }
    </code></pre> <ul> <li>Find-Min : 在根节点队列中遍历寻找 \(O(\log{n})\) 但是如果专门记录更新可以做到 \(O(1)\)</li> <li>Insert：即将一棵 \(B_0\) 树合并到队列中，单次最好 \(O(1)\) 最坏 \(O(\log n)\) ， 均摊 \(O(1)\)</li> <li>Build：将节点逐个插入，由均摊分析得总复杂度 \(O(n)\)</li> <li>DeleteMin：将最小根节点取出，将其对应二项树拆成所有子树再Merge回去， \(O(\log n)\)</li> </ul>  DeleteMin  <pre><code>
    ElementType  DeleteMin( BinQueue H )
    {   
        BinQueue DeletedQueue; 
        Position DeletedTree, OldRoot;
        ElementType MinItem = Infinity;
        int i, j, MinTree;
        if ( IsEmpty( H ) )  {  PrintErrorMessage();  return –Infinity; }
        for ( i = 0; i &lt; MaxTrees; i++) {
            if( H-&gt;TheTrees[i] &amp;&amp; H-&gt;TheTrees[i]-&gt;Element &lt; MinItem ) { 
                MinItem = H-&gt;TheTrees[i]-&gt;Element;  MinTree = i;            } 
        } /* end for-i-loop */
        DeletedTree = H-&gt;TheTrees[ MinTree ];  
        H-&gt;TheTrees[ MinTree ] = NULL;
        OldRoot = DeletedTree; 
        DeletedTree = DeletedTree-&gt;LeftChild;   
        free(OldRoot);
        DeletedQueue = Initialize();    
        DeletedQueue-&gt;CurrentSize = ( 1&lt;= 0; j – – ) {  
            DeletedQueue-&gt;TheTrees[j] = DeletedTree;
            DeletedTree = DeletedTree-&gt;NextSibling;
            DeletedQueue-&gt;TheTrees[j]-&gt;NextSibling = NULL;
        }
        H-&gt;CurrentSize  – = DeletedQueue-&gt;CurrentSize + 1;
        H = Merge( H, DeletedQueue );
        return MinItem;
    }



