        Found = false;
        if ( i &gt; N )return true; /* solved with (x1, ..., xN) */
        for ( each xi in Si ) { 
            /* check if satisfies the restriction R */
            OK = Check((x1, ..., xi) , R ); 
            /* pruning */
            if ( OK ) {
                Count xi in;
                Found = Backtracking( i+1 );
                if ( !Found )Undo( i ); 
                /* recover to (x1, ..., xi-1) */
            }
            if ( Found ) break; 
        }
        return Found;
    }
